// BusinessMetrics groups the overview metrics by data provenance so consumers can tell
// DB-trusted figures from GA4-estimated ones at a glance. BREAKING: replaces the former
// ~90-field flat message — read metrics from commerce / margin / traffic / email instead.
export type BusinessMetrics = {
  period: TimeRange | undefined;
  comparePeriod: TimeRange | undefined;
  commerce: CommerceCoreMetrics | undefined;
  margin: MarginMetrics | undefined;
  traffic: TrafficMetrics | undefined;
  email: EmailMetrics | undefined;
};

// CommerceCoreMetrics is the DB-authoritative commerce view: sales, customers, discounts,
// shipping, plus their breakdowns and daily series.
export type CommerceCoreMetrics = {
  revenue: MetricWithComparison | undefined;
  ordersCount: MetricWithComparison | undefined;
  totalPlacedOrders: MetricWithComparison | undefined;
  avgOrderValue: MetricWithComparison | undefined;
  itemsPerOrder: MetricWithComparison | undefined;
  refundRate: MetricWithComparison | undefined;
  promoUsageRate: MetricWithComparison | undefined;
  grossRevenue: MetricWithComparison | undefined;
  totalRefunded: MetricWithComparison | undefined;
  totalDiscount: MetricWithComparison | undefined;
  productSaleDiscount: MetricWithComparison | undefined;
  promoCodeDiscount: MetricWithComparison | undefined;
  // revenue (field 1) is NET of VAT. revenue_incl_vat is post-discount/refund revenue BEFORE
  // removing VAT (what the company collected); vat_amount = revenue_incl_vat - revenue. VAT is
  // resolved per order from the destination country (0 for export / pre-feature orders).
  revenueInclVat: MetricWithComparison | undefined;
  vatAmount: MetricWithComparison | undefined;
  // unique_customers: distinct buyer emails with a net-revenue order in the period (the
  // "покупатели" KPI). Differs from new_customers (first-ever order in the period) and from
  // clv_distribution.sample_size (distinct emails with non-zero apportioned revenue).
  uniqueCustomers: MetricWithComparison | undefined;
  // peak_day: the single calendar day with the highest net revenue in the period (KPI card).
  // Computed from a daily net-revenue rollup independent of trend_granularity; unset when the
  // period has no revenue.
  peakDay: PeakDay | undefined;
  // discount_rate_pct: total_discount / gross_revenue × 100 — the share of list revenue given
  // away as product-sale + promo discounts (a margin-erosion factor). lower_is_better. Numerator
  // and denominator differ slightly in refunded-order treatment; see caveat.
  discountRatePct: MetricWithComparison | undefined;
  // new_vs_returning: revenue / orders / AOV split by whether the buyer's first-ever order (any
  // status) falls in the period. Complements the existing new/returning_customers_by_day COUNT
  // series with money. new+returning revenue reconciles with headline revenue.
  newVsReturning: NewVsReturningSplit | undefined;
  newSubscribers: MetricWithComparison | undefined;
  newCustomers: MetricWithComparison | undefined;
  repeatCustomersRate: MetricWithComparison | undefined;
  avgOrdersPerCustomer: MetricWithComparison | undefined;
  avgDaysBetweenOrders: MetricWithComparison | undefined;
  avgShippingCost: MetricWithComparison | undefined;
  totalShippingCost: MetricWithComparison | undefined;
  clvDistribution: CLVStats | undefined;
  revenueByCountry: GeographyMetric[] | undefined;
  revenueByCity: GeographyMetric[] | undefined;
  revenueByRegion: RegionMetric[] | undefined;
  avgOrderByCountry: GeographyMetric[] | undefined;
  revenueByCurrency: CurrencyMetric[] | undefined;
  revenueByPaymentMethod: PaymentMethodMetric[] | undefined;
  topProductsByRevenue: ProductMetric[] | undefined;
  topProductsByQuantity: ProductMetric[] | undefined;
  revenueByCategory: CategoryMetric[] | undefined;
  crossSellPairs: CrossSellPair[] | undefined;
  revenueByPromo: PromoMetric[] | undefined;
  // Every order PLACED in the period bucketed by its current status (one per bucket); sums to
  // total_placed_orders, not orders_count.
  ordersByStatus: StatusCount[] | undefined;
  revenueByDay: TimeSeriesPoint[] | undefined;
  ordersByDay: TimeSeriesPoint[] | undefined;
  subscribersByDay: TimeSeriesPoint[] | undefined;
  grossRevenueByDay: TimeSeriesPoint[] | undefined;
  refundsByDay: TimeSeriesPoint[] | undefined;
  avgOrderValueByDay: TimeSeriesPoint[] | undefined;
  unitsSoldByDay: TimeSeriesPoint[] | undefined;
  newCustomersByDay: TimeSeriesPoint[] | undefined;
  returningCustomersByDay: TimeSeriesPoint[] | undefined;
  shippedByDay: TimeSeriesPoint[] | undefined;
  deliveredByDay: TimeSeriesPoint[] | undefined;
  revenueByDayCompare: TimeSeriesPoint[] | undefined;
  ordersByDayCompare: TimeSeriesPoint[] | undefined;
  subscribersByDayCompare: TimeSeriesPoint[] | undefined;
  grossRevenueByDayCompare: TimeSeriesPoint[] | undefined;
  refundsByDayCompare: TimeSeriesPoint[] | undefined;
  avgOrderValueByDayCompare: TimeSeriesPoint[] | undefined;
  unitsSoldByDayCompare: TimeSeriesPoint[] | undefined;
  newCustomersByDayCompare: TimeSeriesPoint[] | undefined;
  returningCustomersByDayCompare: TimeSeriesPoint[] | undefined;
  shippedByDayCompare: TimeSeriesPoint[] | undefined;
  deliveredByDayCompare: TimeSeriesPoint[] | undefined;
};

export type MetricWithComparison = {
  value: googletype_Decimal | undefined;
  compareValue: googletype_Decimal | undefined;
  changePct: number | undefined;
  // When true, a negative change is good (e.g. refund rate, bounce rate). Frontend should show green for decrease, red for increase.
  lowerIsBetter: boolean | undefined;
  // Absolute delta (current - previous) for rate metrics. For percentage/ratio metrics, this is the percentage point change (e.g., 5.0% → 3.0% = -2.0 pp).
  // Frontend should prefer displaying this over change_pct for rate metrics to avoid misleading "rate-of-rates" semantics.
  changeAbsolute: number | undefined;
  // Optional tooltip/caveat text to clarify metric interpretation (e.g., data limitations, calculation notes).
  caveat: string | undefined;
  // Number of observations behind the metric (orders, sessions, customers…). 0 = not
  // populated. Prefer gating a metric on this (e.g. hide/greytext when sample_size < 30)
  // over an arbitrary display floor.
  sampleSize: number | undefined;
  // 95% confidence-interval half-width in the metric's own units (e.g. ±2.4 for a 12.0%
  // rate). Populated only for true count-proportions (conversion, promo usage); 0 = not
  // computed. Frontend can render "12.0% ± 2.4" instead of guessing significance from a floor.
  marginOfError: number | undefined;
};

// PeakDay is the highest-net-revenue calendar day in the reporting period.
export type PeakDay = {
  date: wellKnownTimestamp | undefined;
  revenue: googletype_Decimal | undefined;
  orders: number | undefined;
};

// NewVsReturningSplit breaks the period's net revenue, orders and AOV into new vs returning
// customers. "New" = the buyer's first-ever order (any status) falls in the period; a customer's
// second order in the same period is still counted new (matching the new_customers_by_day series).
export type NewVsReturningSplit = {
  newOrders: MetricWithComparison | undefined;
  newRevenue: MetricWithComparison | undefined;
  newAov: MetricWithComparison | undefined;
  returningOrders: MetricWithComparison | undefined;
  returningRevenue: MetricWithComparison | undefined;
  returningAov: MetricWithComparison | undefined;
  newRevenueSharePct: number | undefined;
  newRevenueByDay: TimeSeriesPoint[] | undefined;
  returningRevenueByDay: TimeSeriesPoint[] | undefined;
};

export type TimeSeriesPoint = {
  date: wellKnownTimestamp | undefined;
  value: googletype_Decimal | undefined;
  count: number | undefined;
};

