  SetMemberStatus(request: SetMemberStatusRequest): Promise<SetMemberStatusResponse>;
  // Soft-delete a member account (status='deleted').
  SoftDeleteMember(request: SoftDeleteMemberRequest): Promise<SoftDeleteMemberResponse>;
  // Hard-erase a member account (GDPR right-to-erasure).
  HardEraseMember(request: HardEraseMemberRequest): Promise<HardEraseMemberResponse>;
  // Get tier transition history for a member.
  GetTierHistory(request: GetTierHistoryRequest): Promise<GetTierHistoryResponse>;
  // Send a custom / event-invite email to a member.
  SendMemberEmail(request: SendMemberEmailRequest): Promise<SendMemberEmailResponse>;
  // Tier configuration (thresholds, expiration, display names).
  GetTierConfig(request: GetTierConfigRequest): Promise<GetTierConfigResponse>;
  UpdateTierConfig(request: UpdateTierConfigRequest): Promise<UpdateTierConfigResponse>;
  // Hacker tier management.
  GenerateHackerInvite(request: GenerateHackerInviteRequest): Promise<GenerateHackerInviteResponse>;
  ListHackerInvites(request: ListHackerInvitesRequest): Promise<ListHackerInvitesResponse>;
  RevokeHackerInvite(request: RevokeHackerInviteRequest): Promise<RevokeHackerInviteResponse>;
  ListHackerAccounts(request: ListHackerAccountsRequest): Promise<ListHackerAccountsResponse>;
  RevokeHackerStatus(request: RevokeHackerStatusRequest): Promise<RevokeHackerStatusResponse>;
  // Tier transition audit log (all members).
  GetTierAuditLog(request: GetTierAuditLogRequest): Promise<GetTierAuditLogResponse>;
  // One-time legacy backfill (admin-triggered).
  RunTierBackfill(request: RunTierBackfillRequest): Promise<RunTierBackfillResponse>;
  // GetCurrentAccount returns the calling account's identity and effective
  // permissions (what its token authorizes). Any authenticated admin may call it;
